class Solution:
    def numTilings(self, n):
        MOD = 10 ** 9 + 7
        if n == 1:
            return 1
        if n == 2:
            return 2
        a, b, c = 1, 1, 2
        for _ in range(3, n + 1):
            nxt = (2 * c + a) % MOD
            a, b, c = b, c, nxt
        return c % MOD

