var numTilings = function(n) {
    const MOD = 1000000007n;
    if (n === 1) return 1;
    if (n === 2) return 2;
    let a = 1n, b = 1n, c = 2n;
    for (let i = 3; i <= n; i++) {
        const nxt = (2n * c + a) % MOD;
        a = b; b = c; c = nxt;
    }
    return Number(c % MOD);
};
